python3 -c "
import sys, json, subprocess
try:
    data = json.load(sys.stdin)
    tool_uses = data.get('tool_uses', [])
    py_modified = False
    for tu in tool_uses:
        tool = tu.get('tool', '')
        if tool in ('Edit', 'Write'):
            fp = tu.get('tool_input', {}).get('file_path', '')
            if fp.endswith('.py'):
                py_modified = True
                break
    if not py_modified:
        sys.exit(0)
    r = subprocess.run(
        ['python', '-m', 'pytest', '-x', '-q', '--tb=short', 'tests/'],
        capture_output=True, text=True, timeout=120
    )
